import{_ as o,o as a,c as t,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"健康检查","description":"","frontmatter":{"read_when":["诊断 WhatsApp 渠道健康状况"],"summary":"渠道连接的健康检查步骤","title":"健康检查","x-i18n":{"generated_at":"2026-02-03T07:47:59Z","model":"claude-opus-4-5","provider":"pi","source_hash":"74f242e98244c135e1322682ed6b67d70f3b404aca783b1bb5de96a27c2c1b01","source_path":"gateway/health.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/health.md","filePath":"zh-CN/gateway/health.md","lastUpdated":1771906665000}'),c={name:"zh-CN/gateway/health.md"};function d(s,e,n,h,i,r){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="健康检查-cli" tabindex="-1"><a class="header-anchor" href="#健康检查-cli">#</a> 健康检查（CLI）</h1><p>验证渠道连接的简短指南，无需猜测。</p><h2 id="快速检查" tabindex="-1"><a class="header-anchor" href="#快速检查">#</a> 快速检查</h2><ul><li><code>opensoul status</code> — 本地摘要：Gateway 网关可达性/模式、更新提示、已链接渠道认证时长、会话 + 最近活动。</li><li><code>opensoul status --all</code> — 完整本地诊断（只读、彩色、可安全粘贴用于调试）。</li><li><code>opensoul status --deep</code> — 还会探测运行中的 Gateway 网关（支持时进行每渠道探测）。</li><li><code>opensoul health --json</code> — 向运行中的 Gateway 网关请求完整健康快照（仅 WS；不直接访问 Baileys 套接字）。</li><li>在 WhatsApp/WebChat 中单独发送 <code>/status</code> 消息可获取状态回复，而不调用智能体。</li><li>日志：跟踪 <code>/tmp/opensoul/opensoul-*.log</code> 并过滤 <code>web-heartbeat</code>、<code>web-reconnect</code>、<code>web-auto-reply</code>、<code>web-inbound</code>。</li></ul><h2 id="深度诊断" tabindex="-1"><a class="header-anchor" href="#深度诊断">#</a> 深度诊断</h2><ul><li>磁盘上的凭证：<code>ls -l ~/.opensoul/credentials/whatsapp/&lt;accountId&gt;/creds.json</code>（mtime 应该是最近的）。</li><li>会话存储：<code>ls -l ~/.opensoul/agents/&lt;agentId&gt;/sessions/sessions.json</code>（路径可在配置中覆盖）。计数和最近收件人通过 <code>status</code> 显示。</li><li>重新链接流程：当日志中出现状态码 409–515 或 <code>loggedOut</code> 时，执行 <code>opensoul channels logout &amp;&amp; opensoul channels login --verbose</code>。（注意：配对后状态 515 时 QR 登录流程会自动重启一次。）</li></ul><h2 id="当出现故障时" tabindex="-1"><a class="header-anchor" href="#当出现故障时">#</a> 当出现故障时</h2><ul><li><code>logged out</code> 或状态 409–515 → 使用 <code>opensoul channels logout</code> 然后 <code>opensoul channels login</code> 重新链接。</li><li>Gateway 网关不可达 → 启动它：<code>opensoul gateway --port 18789</code>（如果端口被占用则使用 <code>--force</code>）。</li><li>没有入站消息 → 确认已链接的手机在线且发送者被允许（<code>channels.whatsapp.allowFrom</code>）；对于群聊，确保允许列表 + 提及规则匹配（<code>channels.whatsapp.groups</code>、<code>agents.list[].groupChat.mentionPatterns</code>）。</li></ul><h2 id="专用-health-命令" tabindex="-1"><a class="header-anchor" href="#专用-health-命令">#</a> 专用&quot;health&quot;命令</h2><p><code>opensoul health --json</code> 向运行中的 Gateway 网关请求其健康快照（CLI 不直接访问渠道套接字）。它报告已链接凭证/认证时长（如可用）、每渠道探测摘要、会话存储摘要和探测持续时间。如果 Gateway 网关不可达或探测失败/超时，它以非零退出。使用 <code>--timeout &lt;ms&gt;</code> 覆盖默认的 10 秒。</p>',10)])])}const _=o(c,[["render",d]]);export{u as __pageData,_ as default};
